import asyncio
import websockets
import json
import uuid
from collections import defaultdict

# In-memory storage for players and items
players = {}
items = defaultdict(list)

# Securely validate and parse incoming data
def validate_and_parse(data):
    try:
        parsed_data = json.loads(data)
        if 'action' not in parsed_data or 'player_id' not in parsed_data:
            raise ValueError("Invalid data format")
        return parsed_data
    except (ValueError, json.JSONDecodeError):
        raise ValueError("Invalid data format")

# Handle player connections
async def handle_player(websocket, path):
    player_id = str(uuid.uuid4())
    players[player_id] = websocket
    try:
        async for message in websocket:
            data = validate_and_parse(message)
            action = data['action']
            if action == 'trade':
                await handle_trade(data)
            elif action == 'inventory':
                await send_inventory(player_id)
    except websockets.exceptions.ConnectionClosed:
        pass
    finally:
        del players[player_id]

# Handle trade action
async def handle_trade(data):
    from_player = data['player_id']
    to_player = data.get('to_player_id')
    item_id = data.get('item_id')

    if not to_player or not item_id:
        return

    if item_id in items[from_player]:
        items[from_player].remove(item_id)
        items[to_player].append(item_id)
        await notify_player(from_player, f"Item {item_id} traded to {to_player}")
        await notify_player(to_player, f"Received item {item_id} from {from_player}")

# Send inventory to player
async def send_inventory(player_id):
    inventory = items[player_id]
    await notify_player(player_id, f"Your inventory: {inventory}")

# Notify player with a message
async def notify_player(player_id, message):
    if player_id in players:
        await players[player_id].send(json.dumps({"message": message}))

# Start the server
async def main():
    async with websockets.serve(handle_player, "localhost", 8765):
        await asyncio.Future()  # Run forever

asyncio.run(main())